function extractContent(item) {
  try {
    const raw = item?.choices?.[0]?.message?.content
              || item?.message?.content
              || item?.text
              || item?.content
              || '{}';
    return JSON.parse(raw.replace(/```json|```/g, '').trim());
  } catch(e) { return {}; }
}

const allItems = $input.all();

// Find each item by its shape
let generatedRaw = null, riskRaw = null, simRaw = null, contextRaw = null;

for (const item of allItems) {
  const j = item.json;
  // Context item has tool field but no choices
  if (j.tool && !j.choices) { contextRaw = j; continue; }
  // Risk analysis has recommendation field in parsed content
  if (j.choices) {
    const parsed = extractContent(j);
    if (parsed.recommendation) { riskRaw = j; }
    else if (parsed.reaction) { simRaw = j; }
    else { generatedRaw = j; }
  }
}

// Fallbacks
if (!riskRaw) riskRaw = allItems[0]?.json ?? {};
if (!simRaw) simRaw = allItems[1]?.json ?? {};
if (!generatedRaw) {
  try { generatedRaw = $('ðŸ¤– OpenAI - Generate Action').first()?.json; } catch(e) {}
  if (!generatedRaw) generatedRaw = allItems[0]?.json ?? {};
}

const riskData = extractContent(riskRaw);
const simData  = extractContent(simRaw);

let generatedContent = {};
try {
  const raw = generatedRaw?.choices?.[0]?.message?.content || '{}';
  generatedContent = JSON.parse(raw.replace(/```json|```/g, '').trim());
} catch(e) { generatedContent = {}; }

const risk = parseInt(riskData.risk_score) || 35;
let finalDecision = 'MODIFY';
if (risk < 30) finalDecision = 'APPROVE';
else if (risk >= 70) finalDecision = 'BLOCK';
const rec = riskData.recommendation;
if (rec === 'APPROVE' || rec === 'BLOCK' || rec === 'MODIFY') finalDecision = rec;

return [{
  decision: finalDecision,
  risk_score: risk,
  tool: contextRaw?.tool || '',
  recipientEmail: contextRaw?.recipientEmail || null,
  prompt: contextRaw?.prompt || '',
  result: generatedContent,
  generated: generatedContent,
  risk_analysis: Object.keys(riskData).length ? riskData : { risk_score: risk, issues: [], recommendation: finalDecision },
  simulation: Object.keys(simData).length ? simData : { reaction: 'neutral', sentiment_score: 50, likely_response: 'Pending.' },
  timestamp: new Date().toISOString()
}];

