const prev = $input.first().json;
const rewritten = prev.choices?.[0]?.message?.content || '';
let rewrittenParsed = {};
try { rewrittenParsed = JSON.parse(rewritten.replace(/```json|```/g, '').trim()); } catch(e) {}

return [{
  decision: 'MODIFY',
  risk_score: prev.risk_score,
  tool: prev.tool,
  recipientEmail: prev.recipientEmail || null,
  generated: prev.generated,
  rewritten: rewrittenParsed,
  risk_analysis: prev.risk_analysis,
  simulation: prev.simulation,
  timestamp: new Date().toISOString()
}];

return [{
  decision: 'BLOCK',
  risk_score: $json.risk_score,
  message: 'Content blocked due to high risk. Please revise your prompt.',
  issues: $json.risk_analysis?.issues || [],
  status: 'blocked'
}];
